package ru.memearena.meme.api; import ru.memearena.meme.domain.*; import java.time.Instant; import java.util.UUID; public record MemeResponse(UUID id,String title,String imageUrl,UUID mediaAssetId,String contentUrl,String sourceUrl,ModerationStatus moderationStatus,String moderationReason,int rating,long wins,long losses,long battlesCount,Instant createdAt){ public static MemeResponse from(Meme m){String cu=m.getMediaAssetId()!=null?"/api/v1/media/"+m.getMediaAssetId()+"/content":m.getImageUrl(); return new MemeResponse(m.getId(),m.getTitle(),m.getImageUrl(),m.getMediaAssetId(),cu,m.getSourceUrl(),m.getModerationStatus(),m.getModerationReason(),m.getRating(),m.getWins(),m.getLosses(),m.getBattlesCount(),m.getCreatedAt());}}
